// ============================================
// SPLIT MARKDOWN INTO NOTION-SAFE BLOCKS
// ============================================

// Get the input data from previous node
const data = $input.first().json;

// Function to split markdown text into chunks that fit Notion's block size limits
function splitMarkdown(text, maxLength = 1900) {
  const chunks = [];        // Array to store the split chunks
  let current = '';         // Current chunk being built

  // Split the full markdown by double newlines (paragraph breaks)
  // This keeps paragraphs together instead of cutting mid-paragraph
  const paragraphs = text.split('\n\n');

  // Loop through each paragraph
  for (const para of paragraphs) {
    // Check if adding this paragraph would exceed the max length
    if ((current + para).length > maxLength && current) {
      // Current chunk is full, save it and start a new one
      chunks.push(current.trim());
      current = para;  // Start new chunk with current paragraph
    } else {
      // There's room, add this paragraph to current chunk
      // Add '\n\n' separator if current chunk already has content
      current += (current ? '\n\n' : '') + para;
    }
  }

  // Don't forget to push the last chunk if it has content
  if (current) {
    chunks.push(current.trim());
  }

  return chunks;  // Return array of markdown chunks
}

// Split the full markdown into chunks
const markdownChunks = splitMarkdown(data.full_markdown);

// ============================================
// RETURN DATA WITH SPLIT BLOCKS
// ============================================

return [{
  json: {
    ...data,  // Keep all existing fields (id, topic, etc.)
    // Add up to 5 markdown blocks (empty string if chunk doesn't exist)
    markdown_block_1: markdownChunks[0] || '',
    markdown_block_2: markdownChunks[1] || '',
    markdown_block_3: markdownChunks[2] || '',
    markdown_block_4: markdownChunks[3] || '',
    markdown_block_5: markdownChunks[4] || '',
  }
}];

const digest = $('Select Digest').item.json;
const style = $('Style Lookup').first().json;

// Topic emojis
const topicEmojis = { 'AI': '🤖', 'Finance': '💰', 'Music': '🎵', 'Science': '🔬' };
const topic = style.topic_category;
const emoji = topicEmojis[topic] || '📊';

// Period display
const periodStart = digest.period_start.split('T')[0];
const periodEnd = digest.period_end.split('T')[0];
const periodDisplay = `${periodStart} ${periodEnd}`;

// Topic-specific content
const topicConfig = {
  'AI': {
    audience: 'recruiters and talent leaders',
    title: 'AI News',
    cta: 'Stay ahead of AI talent trends'
  },
  'Finance': {
    audience: 'investors and financial advisors',
    title: 'Finance News',
    cta: 'Track market insights'
  },
  'Music': {
    audience: 'industry professionals and artists',
    title: 'Music Industry News',
    cta: 'Stay ahead of music trends'
  },
  'Science': {
    audience: 'researchers and science professionals',
    title: 'Science News',
    cta: 'Discover breakthrough research'
  }
};

const config = topicConfig[topic] || { audience: 'professionals', title: `${topic} News`, cta: 'Stay informed' };

// Extract theme sentence from digest
const themeSentence = digest.dominant_topic || `${topic} trends emerging`;

// Extract sources from Style Lookup
const sources = style.source_names || 'various sources';

// BUILD INFOGRAPHIC PROMPT
const blocks = [];

// BLOCK 1: Intro with audience
blocks.push(`Modern corporate infographic for ${topic} news digest targeting ${config.audience}.`);

// BLOCK 2: Design (using colors from style table)
blocks.push(`DESIGN: ${style.primary_color || '#0F172A'} background, ${style.secondary_color || '#38BDF8'} headers, ${style.accent_color || '#06BDF4'} cards/metrics, off-white text (#F1F5F9). Inter font family. Clean minimal style, generous whitespace, 3-column grid.`);

// BLOCK 3: Structure
blocks.push(`STRUCTURE:
1. Subtle header
2. Title: "${config.title}" + theme: "${themeSentence}"
3. 3-4 highlighted key metrics/stats (large numbers)
4. 3 bullet insights
5. CTA button: "${config.cta}"
6. Subtle footer`);

// BLOCK 4: Header
blocks.push(`HEADER:
- Top left: "The 3-Days News Digest"
- Top right: ${periodDisplay}`);

// BLOCK 5: Footer
blocks.push(`FOOTER:
- Sources: ${sources}
- Automation stack: n8n + Postgres
- Processed by AI`);

// BLOCK 6: Quality checks (static)
blocks.push(`QUALITY CHECKS (MANDATORY):
- PERFECT TEXT: Crisp, readable letters—no garbling, distortion, illegible words, or overlapping
- NO ARTIFACTS: Clean edges, no floating elements, no blurry gradients or pixelation
- ACCURATE DATA: Every metric/insight DIRECTLY from source—NO invented numbers
- HIGH CONTRAST: All text 4.5:1 ratio minimum, fully legible on mobile
- SIMPLE SHAPES: Sharp rectangles/circles only—no complex patterns or textures
- ALIGNED ELEMENTS: Perfect grid alignment, equal spacing, no overlaps

Elegant, professional, high-contrast, no clutter. Generate flawless typography and source-accurate content.

REFINEMENTS:
- Metric numbers LARGER/bolder (e.g., "3 Pillars" → "3" huge with accent color)
- Bullet dots → numbered icons (1,2,3) for scannability
- CTA: Add subtle shadow/glow for 3D pop
- Header and footer: Slightly smaller (reduce clutter)`);

// Return all data
return [{
  json: {
    ...digest,
    ...style,
    topic_emoji: emoji,
    period_display: periodDisplay,
    infographic_prompt: blocks.join('\n\n'),
    notion_title: `${emoji} 3-Day ${topic} Digest: ${style.dominant_topic}`,
    email_subject: `${emoji} Your 3-Day ${topic} Digest is Ready!`,
    gdoc_title: `${topic} Digest | ${periodDisplay}`
  }
}];

// Check if we distributed a digest (Send Mail node executed)
let hasDistribution = false;
let notionUrl = null;
let gdocId = null;

try {
  // Try to get distribution results
  const sendMailNode = $('Send Mail').all();
  hasDistribution = sendMailNode.length > 0;

  if (hasDistribution) {
    // Get Notion URL
    const notionNode = $('Create Notion digest page').all();
    if (notionNode.length > 0 && notionNode[0].json.url) {
      notionUrl = notionNode[0].json.url;
    }

    // Get Google Doc ID
    const gdocNode = $('Create Google Doc digest').all();
    if (gdocNode.length > 0 && gdocNode[0].json.documentId) {
      gdocId = gdocNode[0].json.documentId;
    }
  }
} catch (error) {
  // Nodes didn't execute (FALSE branch), hasDistribution remains false
  hasDistribution = false;
}

return [{
  json: {
    topic: 'unknown',
    workflow_id: 4,
    event: hasDistribution ? 'distribution_complete' : 'no_digest_to_distribute',
    status: 'success',
    details: hasDistribution ? {
      notion_url: notionUrl,
      gdoc_id: gdocId,
      email_sent: true
    } : {
      message: 'No unpublished digest found'
    }
  }
}];

